SELECT e.id AS doctorId, e.realname AS doctorName, e.title_level AS titleLevel, s.schedule_date AS scheduleDate, s.noon AS noon, s.regist_quota AS registQuota, d.dept_name AS deptName, rl.regist_fee AS registFee FROM scheduling s LEFT JOIN employee e ON s.employee_id = e.id LEFT JOIN department d ON s.deptment_id = d.id LEFT JOIN regist_level rl ON e.regist_level_id = rl.id WHERE s.deptment_id = #{deptId} AND s.schedule_date = #{visitDate} AND s.schedule_status = 'ACTIVE'
AND s.noon = #{noon}
ORDER BY e.id LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM scheduling s
WHERE s.deptment_id = #{deptId}
AND s.schedule_date = #{visitDate}
AND s.schedule_status = 'ACTIVE'

    AND s.noon = #{noon}

SELECT * FROM scheduling
WHERE 1=1
AND deptment_id = #{deptId}
AND employee_id = #{employeeId}
AND schedule_date >= #{startDate}
AND schedule_date <= #{endDate}
ORDER BY schedule_date, noon

SELECT s.*, e.realname as doctorName, e.title_level
FROM scheduling s
         JOIN employee e ON s.employee_id = e.id
WHERE s.deptment_id = #{deptId}
  AND s.schedule_date = #{scheduleDate}
  AND s.noon = #{noon}
  AND s.schedule_status = 'NORMAL'
  AND e.delmark = TRUE
